## What to Implement

### 1. Enhanced DatabaseSchema Types
```rust
// In sqlmodel-schema/src/introspect.rs

/// Complete representation of a database schema.
#[derive(Debug, Clone)]
pub struct DatabaseSchema {
    /// All tables in the schema
    pub tables: HashMap<String, TableSchema>,

    /// Database version/dialect info
    pub dialect: Dialect,
}

/// Complete representation of a table.
#[derive(Debug, Clone)]
pub struct TableSchema {
    pub name: String,
    pub columns: Vec<ColumnSchema>,
    pub primary_key: Option<PrimaryKeySchema>,
    pub foreign_keys: Vec<ForeignKeySchema>,
    pub unique_constraints: Vec<UniqueConstraintSchema>,
    pub indexes: Vec<IndexSchema>,
    pub check_constraints: Vec<CheckConstraintSchema>,
}

/// Complete representation of a column.
#[derive(Debug, Clone)]
pub struct ColumnSchema {
    pub name: String,
    pub sql_type: String,          // Raw SQL type string
    pub nullable: bool,
    pub default: Option<String>,   // Default expression
    pub auto_increment: bool,
    pub comment: Option<String>,   // Column comment if any

    // Parsed type info
    pub parsed_type: ParsedSqlType,
}

/// Parsed SQL type with extracted metadata.
#[derive(Debug, Clone)]
pub struct ParsedSqlType {
    pub base_type: String,         // VARCHAR, INTEGER, DECIMAL, etc.
    pub length: Option<u32>,       // VARCHAR(255) -> 255
    pub precision: Option<u32>,    // DECIMAL(10,2) -> 10
    pub scale: Option<u32>,        // DECIMAL(10,2) -> 2
    pub unsigned: bool,            // INT UNSIGNED
    pub array: bool,               // PostgreSQL array types
}

/// Primary key constraint.
#[derive(Debug, Clone)]
pub struct PrimaryKeySchema {
    pub name: Option<String>,      // Constraint name
    pub columns: Vec<String>,      // Column(s) in PK
}

/// Foreign key constraint.
#[derive(Debug, Clone)]
pub struct ForeignKeySchema {
    pub name: Option<String>,
    pub columns: Vec<String>,
    pub referenced_table: String,
    pub referenced_columns: Vec<String>,
    pub on_delete: Option<String>,
    pub on_update: Option<String>,
}

/// Unique constraint.
#[derive(Debug, Clone)]
pub struct UniqueConstraintSchema {
    pub name: Option<String>,
    pub columns: Vec<String>,
}

/// Index definition.
#[derive(Debug, Clone)]
pub struct IndexSchema {
    pub name: String,
    pub columns: Vec<String>,
    pub unique: bool,
    pub index_type: Option<String>, // BTREE, HASH, etc.
}
```

### 2. SQLite Introspection
```rust
pub async fn introspect_sqlite(conn: &impl Connection) -> Result<DatabaseSchema> {
    let mut schema = DatabaseSchema::new(Dialect::Sqlite);

    // List all tables
    let tables = conn.query(
        "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'",
        &[]
    ).await?;

    for table_row in tables {
        let table_name: String = table_row.get("name")?;
        let mut table = TableSchema::new(&table_name);

        // Get column info
        let cols = conn.query(
            &format!("PRAGMA table_info('{}')", table_name),
            &[]
        ).await?;

        for col in cols {
            table.columns.push(ColumnSchema {
                name: col.get("name")?,
                sql_type: col.get("type")?,
                nullable: col.get::<i32>("notnull")? == 0,
                default: col.get("dflt_value").ok(),
                auto_increment: false, // Check via AUTOINCREMENT in CREATE
                comment: None,
                parsed_type: parse_sql_type(&col.get::<String>("type")?),
            });

            if col.get::<i32>("pk")? > 0 {
                table.primary_key = Some(PrimaryKeySchema {
                    name: None,
                    columns: vec![col.get("name")?],
                });
            }
        }

        // Get foreign keys
        let fks = conn.query(
            &format!("PRAGMA foreign_key_list('{}')", table_name),
            &[]
        ).await?;

        for fk in fks {
            table.foreign_keys.push(ForeignKeySchema {
                name: None,
                columns: vec![fk.get("from")?],
                referenced_table: fk.get("table")?,
                referenced_columns: vec![fk.get("to")?],
                on_delete: fk.get("on_delete").ok(),
                on_update: fk.get("on_update").ok(),
            });
        }

        // Get indexes
        let indexes = conn.query(
            &format!("PRAGMA index_list('{}')", table_name),
            &[]
        ).await?;

        for idx in indexes {
            let idx_name: String = idx.get("name")?;
            let idx_info = conn.query(
                &format!("PRAGMA index_info('{}')", idx_name),
                &[]
            ).await?;

            table.indexes.push(IndexSchema {
                name: idx_name,
                columns: idx_info.iter().map(|r| r.get("name").unwrap()).collect(),
                unique: idx.get::<i32>("unique")? == 1,
                index_type: None,
            });
        }

        schema.tables.insert(table_name, table);
    }

    Ok(schema)
}
```

### 3. PostgreSQL Introspection
```rust
pub async fn introspect_postgres(conn: &impl Connection) -> Result<DatabaseSchema> {
    let mut schema = DatabaseSchema::new(Dialect::Postgres);

    // Get all tables
    let tables = conn.query(
        "SELECT table_name FROM information_schema.tables 
         WHERE table_schema = 'public' AND table_type = 'BASE TABLE'",
        &[]
    ).await?;

    for table_row in tables {
        let table_name: String = table_row.get("table_name")?;
        let mut table = TableSchema::new(&table_name);

        // Get columns
        let cols = conn.query(
            "SELECT column_name, data_type, character_maximum_length,
                    numeric_precision, numeric_scale, is_nullable,
                    column_default, udt_name
             FROM information_schema.columns
             WHERE table_name = $1
             ORDER BY ordinal_position",
            &[table_name.clone().into()]
        ).await?;

        for col in cols {
            let sql_type = build_postgres_type(&col);
            table.columns.push(ColumnSchema {
                name: col.get("column_name")?,
                sql_type: sql_type.clone(),
                nullable: col.get::<String>("is_nullable")? == "YES",
                default: col.get("column_default").ok(),
                auto_increment: col.get::<String>("column_default")
                    .map(|d| d.starts_with("nextval"))
                    .unwrap_or(false),
                comment: None,
                parsed_type: parse_sql_type(&sql_type),
            });
        }

        // Get primary key
        let pk = conn.query(
            "SELECT a.attname
             FROM pg_index i
             JOIN pg_attribute a ON a.attrelid = i.indrelid AND a.attnum = ANY(i.indkey)
             WHERE i.indrelid = $1::regclass AND i.indisprimary",
            &[table_name.clone().into()]
        ).await?;

        if !pk.is_empty() {
            table.primary_key = Some(PrimaryKeySchema {
                name: None,
                columns: pk.iter().map(|r| r.get("attname").unwrap()).collect(),
            });
        }

        // Get foreign keys
        let fks = conn.query(
            "SELECT
                tc.constraint_name,
                kcu.column_name,
                ccu.table_name AS foreign_table_name,
                ccu.column_name AS foreign_column_name,
                rc.delete_rule,
                rc.update_rule
             FROM information_schema.table_constraints AS tc
             JOIN information_schema.key_column_usage AS kcu
                ON tc.constraint_name = kcu.constraint_name
             JOIN information_schema.constraint_column_usage AS ccu
                ON ccu.constraint_name = tc.constraint_name
             JOIN information_schema.referential_constraints AS rc
                ON rc.constraint_name = tc.constraint_name
             WHERE tc.constraint_type = 'FOREIGN KEY' AND tc.table_name = $1",
            &[table_name.clone().into()]
        ).await?;

        // ... process FKs

        // Get indexes
        let indexes = conn.query(
            "SELECT indexname, indexdef FROM pg_indexes WHERE tablename = $1",
            &[table_name.clone().into()]
        ).await?;

        // ... process indexes

        schema.tables.insert(table_name, table);
    }

    Ok(schema)
}
```

### 4. MySQL Introspection
```rust
pub async fn introspect_mysql(conn: &impl Connection) -> Result<DatabaseSchema> {
    let mut schema = DatabaseSchema::new(Dialect::Mysql);

    // Get database name from connection
    let db_name = conn.current_database().await?;

    // Get tables
    let tables = conn.query(
        "SELECT table_name FROM information_schema.tables 
         WHERE table_schema = ?",
        &[db_name.clone().into()]
    ).await?;

    for table_row in tables {
        let table_name: String = table_row.get("table_name")?;
        let mut table = TableSchema::new(&table_name);

        // Get columns using SHOW COLUMNS for more detail
        let cols = conn.query(
            &format!("SHOW FULL COLUMNS FROM `{}`", table_name),
            &[]
        ).await?;

        for col in cols {
            let col_type: String = col.get("Type")?;
            table.columns.push(ColumnSchema {
                name: col.get("Field")?,
                sql_type: col_type.clone(),
                nullable: col.get::<String>("Null")? == "YES",
                default: col.get("Default").ok(),
                auto_increment: col.get::<String>("Extra")?.contains("auto_increment"),
                comment: col.get("Comment").ok(),
                parsed_type: parse_sql_type(&col_type),
            });
        }

        // Get primary key and indexes
        let indexes = conn.query(
            &format!("SHOW INDEX FROM `{}`", table_name),
            &[]
        ).await?;

        // ... process indexes and PK

        // Get foreign keys
        let fks = conn.query(
            "SELECT constraint_name, column_name, referenced_table_name,
                    referenced_column_name
             FROM information_schema.key_column_usage
             WHERE table_schema = ? AND table_name = ? 
               AND referenced_table_name IS NOT NULL",
            &[db_name.clone().into(), table_name.clone().into()]
        ).await?;

        // ... process FKs

        schema.tables.insert(table_name, table);
    }

    Ok(schema)
}
```

