pub async fn introspect(conn: &impl Connection) -> Result<DatabaseSchema> {
    match conn.dialect() {
        Dialect::Sqlite => introspect_sqlite(conn).await,
        Dialect::Postgres => introspect_postgres(conn).await,
        Dialect::Mysql => introspect_mysql(conn).await,
    }
}
